(async () => {
  try {
    const bannerBtn = document.querySelector('button[aria-label="Add banner photo"]');
    if (!bannerBtn) {
      return { didAction: false, reason: 'banner photo button not found' };
    }
    // 親要素からinput要素を探す
    const parent = bannerBtn.parentElement;
    if (!parent) {
      return { didAction: false, reason: 'banner photo button parent not found' };
    }
    const fileInput = parent.querySelector('input[type="file"][data-testid="fileInput"]');
    if (!fileInput) {
      return { didAction: false, reason: 'banner photo file input not found' };
    }
    // 一時的なdata属性を追加して識別可能にする
    fileInput.setAttribute('data-banner-input', 'true');
    return { didAction: true, reason: 'banner photo input identified' };
  } catch (e) {
    return { didAction: false, reason: String(e) };
  }
})()

(async () => {
  try {
    const bannerImagePath = "{{banner_image_path}}";
    // 未指定の場合はスキップ
    if (!bannerImagePath || bannerImagePath.trim() === '') {
      return { didAction: true, skipped: true, reason: 'banner_image_path not provided, skipping' };
    }

    // Edit mediaモーダルを探す（タイトルが"Edit media"のモーダル）
    let modal = null;
    const allModals = document.querySelectorAll('[role="dialog"]');
    for (const m of allModals) {
      const header = m.querySelector('h2[id="modal-header"]') || m.querySelector('[aria-labelledby="modal-header"]');
      if (header) {
        const titleText = header.textContent?.trim() || '';
        if (titleText === 'Edit media' || titleText.includes('Edit media')) {
          modal = m;
          break;
        }
      }
    }

    if (!modal) {
      // モーダルが見つからない場合は、既に閉じられているか、表示されていない可能性がある
      return { didAction: true, skipped: true, reason: 'Edit media modal not found, may already be closed' };
    }

    // Applyボタンを探す
    let applyBtn = null;
    const buttons = modal.querySelectorAll('button');
    for (const btn of buttons) {
      const text = btn.textContent?.trim() || '';
      if (text === 'Apply' || text.includes('Apply')) {
        applyBtn = btn;
        break;
      }
    }

    if (!applyBtn) {
      return { didAction: false, reason: 'Apply button not found in Edit media modal' };
    }

    // ボタンが無効化されている場合は有効になるまで待つ
    let waitCount = 0;
    while ((applyBtn.disabled || applyBtn.getAttribute('aria-disabled') === 'true') && waitCount < 20) {
      await new Promise(r => setTimeout(r, 500));
      applyBtn = modal.querySelector('button');
      if (!applyBtn) {
        return { didAction: false, reason: 'Apply button disappeared' };
      }
      const text = applyBtn.textContent?.trim() || '';
      if (text === 'Apply' || text.includes('Apply')) {
        // 見つかった
      } else {
        // 別のボタンかもしれないので、再度検索
        const buttons = modal.querySelectorAll('button');
        for (const btn of buttons) {
          const btnText = btn.textContent?.trim() || '';
          if (btnText === 'Apply' || btnText.includes('Apply')) {
            applyBtn = btn;
            break;
          }
        }
      }
      waitCount++;
    }

    applyBtn.click();
    await new Promise(r => setTimeout(r, 2000));

    // モーダルが閉じられるまで待つ
    let checkCount = 0;
    while (checkCount < 20) {
      const stillOpen = document.querySelector('[role="dialog"]');
      if (!stillOpen || !stillOpen.contains(modal)) {
        return { didAction: true, reason: 'Apply button clicked, modal closed' };
      }
      await new Promise(r => setTimeout(r, 500));
      checkCount++;
    }

    return { didAction: true, reason: 'Apply button clicked' };
  } catch (e) {
    return { didAction: false, reason: String(e) };
  }
})()

