(async () => {
  try {
    const name = "{{name}}";
    // 未指定の場合はスキップ
    if (!name || name.trim() === '') {
      return { didAction: true, skipped: true, reason: 'name not provided, skipping' };
    }

    const nameInput = document.querySelector('input[name="displayName"]');
    if (!nameInput) {
      return { didAction: false, reason: 'name input not found' };
    }

    // フォーカスしてクリック
    nameInput.focus();
    nameInput.click();
    await new Promise(r => setTimeout(r, 500));

    // 既存の内容を全選択
    nameInput.select();
    await new Promise(r => setTimeout(r, 200));

    // 1文字ずつキー入力で入力
    for (let i = 0; i < name.length; i++) {
      const char = name[i];
      nameInput.dispatchEvent(new KeyboardEvent('keydown', { bubbles: true, cancelable: true, key: char, code: char.charCodeAt(0) }));
      nameInput.dispatchEvent(new KeyboardEvent('keypress', { bubbles: true, cancelable: true, key: char, code: char.charCodeAt(0) }));
      if (document.execCommand) {
        document.execCommand('insertText', false, char);
      } else {
        // execCommandが使えない場合は直接値を設定（フォールバック）
        const start = nameInput.selectionStart || 0;
        const end = nameInput.selectionEnd || 0;
        const currentValue = nameInput.value || '';
        nameInput.value = currentValue.slice(0, start) + char + currentValue.slice(end);
        nameInput.setSelectionRange(start + 1, start + 1);
      }
      nameInput.dispatchEvent(new KeyboardEvent('keyup', { bubbles: true, cancelable: true, key: char, code: char.charCodeAt(0) }));
      nameInput.dispatchEvent(new Event('input', { bubbles: true, cancelable: true }));
      await new Promise(r => setTimeout(r, 10));
    }

    await new Promise(r => setTimeout(r, 500));
    nameInput.dispatchEvent(new Event('input', { bubbles: true, cancelable: true }));
    nameInput.dispatchEvent(new Event('change', { bubbles: true, cancelable: true }));
    await new Promise(r => setTimeout(r, 300));

    return { didAction: true, reason: 'name entered', value: name };
  } catch (e) {
    return { didAction: false, reason: String(e) };
  }
})()

